import pyjpeg


def test_dqt():
    tables = [
        pyjpeg.QuantizationTable(1, [1] * 64, precision=8),
        pyjpeg.QuantizationTable(3, [3] * 64, precision=16),
    ]

    writer = pyjpeg.BufferedWriter()
    pyjpeg.DefineQuantizationTables(tables).write(writer)
    assert (
        writer.data.hex()
        == ""
    )

    reader = pyjpeg.BufferedReader(writer.data)
    dqt = pyjpeg.DefineQuantizationTables.read(reader)
    assert dqt.tables == tables
